## Part 2: Implement SupabaseAuthProvider

**File to Create:** src/server/auth/supabase-provider.ts

### Implementation Structure:

```typescript
import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'
import type { SupabaseClient } from '@supabase/supabase-js'

export class SupabaseAuthProvider implements IAuthProvider {
  private serviceRoleClient: SupabaseClient  // For admin operations

  constructor() {
    this.serviceRoleClient = createClient(
      process.env.SUPABASE_SERVICE_ROLE_KEY!
    )
  }

  // For user-context operations (respects RLS)
  private getServerClient() {
    return createServerClient(
      {
        cookies: {
          get: (name) => cookies().get(name)?.value,
          set: (name, value, options) => cookies().set(name, value, options),
          remove: (name, options) => cookies().set(name, '', options),
        },
      }
    )
  }

  async authenticateWithPassword(email: string, password: string): Promise<User | null> {
    const supabase = this.getServerClient()
    const { data, error } = await supabase.auth.signInWithPassword({ email, password })


    // Fetch user_profiles for role and namespace
    const { data: profile } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', data.user.id)
      .single()


    return this.mapToUser(data.user, profile)
  }

  async signUp(email, password, username, role, namespaceId): Promise<User> {
    // 1. Create auth.users via Supabase Auth
    const { data, error } = await this.serviceRoleClient.auth.admin.createUser({
      email,
      password,
      email_confirm: false,  // Disable for local dev
      user_metadata: { username }
    })


    // 2. Create user_profiles row
    const { error: profileError } = await this.serviceRoleClient
      .from('user_profiles')
      .insert({
        id: data.user.id,
        username,
        role,
        namespace_id: namespaceId,
        display_name: username
      })

    if (profileError) {
      // Rollback: delete auth user
      await this.serviceRoleClient.auth.admin.deleteUser(data.user.id)
      throw new Error(`Profile creation failed: ${profileError.message}`)
    }

    return this.mapToUser(data.user, { username, role, namespace_id: namespaceId })
  }

  async getSessionFromRequest(request: NextRequest): Promise<AuthSession | null> {
    // Extract JWT from cookies and validate
    const supabase = createServerClient(
      {
        cookies: {
          get: (name) => request.cookies.get(name)?.value,
        },
      }
    )

    const { data: { session }, error } = await supabase.auth.getSession()

    // Fetch user profile
    const { data: profile } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', session.user.id)
      .single()


    return {
      sessionId: session.access_token,  // Use JWT as sessionId
      user: this.mapToUser(session.user, profile),
      expiresAt: new Date(session.expires_at! * 1000).toISOString()
    }
  }

  // Legacy methods (keep for backward compatibility during migration)
  async authenticate(username: string): Promise<User | null> {
    // Lookup email from user_profiles, but this requires password
    // For now, throw error directing to new method
    throw new Error('Use authenticateWithPassword(email, password) instead')
  }

  async createSession(user: User): Promise<AuthSession> {
    // Supabase creates sessions automatically during signIn
    // This is called after authenticate(), so we can return a stub
    throw new Error('Sessions are created automatically by Supabase Auth')
  }

  async getSession(sessionId: string): Promise<AuthSession | null> {
    // For JWT-based sessions, sessionId is the access token
    // Validate JWT and return session
    const { data: { user }, error } = await this.serviceRoleClient.auth.getUser(sessionId)

    const { data: profile } = await this.serviceRoleClient
      .from('user_profiles')
      .select('*')
      .eq('id', user.id)
      .single()


    return {
      sessionId,
      user: this.mapToUser(user, profile),
      expiresAt: new Date(Date.now() + 3600000).toISOString()  // 1 hour from now
    }
  }

  private mapToUser(authUser: any, profile: any): User {
    return {
      id: authUser.id,
      username: profile.username,
      role: profile.role,
      namespaceId: profile.namespace_id,
      displayName: profile.display_name,
      createdAt: authUser.created_at,
      lastLoginAt: profile.last_login_at,
      emailConfirmed: authUser.email_confirmed_at != null
    }
  }

  // Implement remaining IAuthProvider methods...
  // getUser, getUserByUsername, updateUser, deleteUser, etc.
}
```

