Create Next.js middleware to refresh Supabase auth sessions on every request.

## File to Create

**src/middleware.ts**

### Implementation

```typescript
import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

/**
 * Middleware runs on every request to refresh Supabase sessions.
 * This ensures JWT tokens are kept fresh and cookies are updated.
 */
export async function middleware(request: NextRequest) {
  let response = NextResponse.next({
    request: {
      headers: request.headers,
    },
  })

  const supabase = createServerClient(
    {
      cookies: {
        get(name: string) {
          return request.cookies.get(name)?.value
        },
        set(name: string, value: string, options: any) {
          // Update both the request and response cookies
          request.cookies.set({
            name,
            value,
            ...options,
          })
          response.cookies.set({
            name,
            value,
            ...options,
          })
        },
        remove(name: string, options: any) {
          request.cookies.set({
            name,
            value: '',
            ...options,
          })
          response.cookies.set({
            name,
            value: '',
            ...options,
          })
        },
      },
    }
  )

  // This will refresh session if expired and update cookies
  await supabase.auth.getSession()

  return response
}

// Configure which routes the middleware runs on
export const config = {
  matcher: [
    /*
     * Match all request paths except for the ones starting with:
     * - _next/static (static files)
     * - _next/image (image optimization files)
     * - favicon.ico (favicon file)
     * - public folder
     */
    '/((?!_next/static|_next/image|favicon.ico|.*\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',
  ],
}
```

## Key Features

1. **Automatic Session Refresh:** 
   - Runs on every request matched by config.matcher
   - Calls supabase.auth.getSession() which auto-refreshes if needed
   - Updates cookies in both request and response

2. **Cookie Management:**
   - Implements get/set/remove for Supabase SSR
   - Updates both request (for downstream handlers) and response (for client)
   - Properly handles httpOnly, secure, sameSite options

3. **Route Matching:**
   - Runs on all routes except static assets
   - Includes API routes for server-side session refresh
   - Includes page routes for client-side navigation

## Integration with Auth System

This middleware works alongside SupabaseAuthProvider:
- Middleware: Refreshes sessions passively on every request
- Auth routes: Actively create/destroy sessions
- Protected routes: Read session via getSessionFromRequest()

## Performance Considerations

- Middleware runs on EVERY matched request (could be 10+ per page load)
- getSession() is fast when session is valid (just cookie read)
- Only hits Supabase API when token needs refresh (every ~1 hour)
- Consider caching strategy if performance becomes an issue

## Testing

**Create:** src/middleware.test.ts

- Mock createServerClient
- Test session refresh on valid token
- Test session refresh on expired token
- Test cookie propagation (request + response)
- Test route matching (includes API, excludes static)

## Environment Variables Required

- NEXT_PUBLIC_SUPABASE_URL
- NEXT_PUBLIC_SUPABASE_ANON_KEY

