## Part 3: Update WebSocket Authentication

### src/server/websocket-handler.ts

**Current approach:** Extract sessionId from URL query params, call authProvider.getSession(sessionId)

**New approach:** Extract JWT from cookies or Authorization header

```typescript
export async function handleUpgrade(
  request: IncomingMessage,
  socket: Duplex,
  head: Buffer
): Promise<void> {
  try {
    // Extract JWT from cookies
    const cookies = parseCookies(request.headers.cookie || '');
    const accessToken = cookies['sb-access-token'];

      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
      socket.destroy();
      return;
    }

    // Validate JWT and get user
    const authProvider = await getAuthProvider();
    const session = await authProvider.getSession(accessToken);  // Uses JWT as sessionId

      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
      socket.destroy();
      return;
    }

    // Upgrade to WebSocket with authenticated user
    wss.handleUpgrade(request, socket, head, (ws) => {
      const authWs = ws as AuthenticatedWebSocket;
      authWs.user = session.user;
      authWs.sessionId = session.sessionId;
      wss.emit('connection', authWs, request);
    });
  } catch (error) {
    console.error('[WebSocket] Upgrade error:', error);
    socket.destroy();
  }
}

// Helper function to parse cookies
function parseCookies(cookieHeader: string): Record<string, string> {
  const cookies: Record<string, string> = {};
  cookieHeader.split(';').forEach(cookie => {
    const [name, value] = cookie.trim().split('=');
    if (name && value) {
      cookies[name] = decodeURIComponent(value);
    }
  });
  return cookies;
}
```

